('esports-player','Pemain E-Sports Profesional','Sports','Jadilah atlet e-sports profesional yang mendominasi panggung kompetitif global. Reaksi cepat, strategi matang, dan kerja sama tim adalah senjatamu.','🎮','#6366F1','["Memenangkan turnamen lokal pertama","Masuk tim e-sports profesional","Juara turnamen nasional","Mendapat sponsor resmi","Juara turnamen Asia Tenggara","Tampil di kejuaraan dunia","Pensiun sebagai legenda e-sports"]'::jsonb,'["Warm-up aim drill 20 menit","Review meta game terbaru","Sesi scrim dengan tim","Analisis gameplay lawan","Latihan komunikasi tim","Streaming & interaksi fans","Stretching jari & pergelangan"]'::jsonb,'[{"dimension": "Latihan Mekanik", "items": ["Aim trainer 30 menit", "Drill combo skill", "Reaction time test"]},{"dimension": "Strategi Game", "items": ["Review patch notes", "Pelajari meta terbaru", "Analisis draft/pick phase"]},{"dimension": "Scrim & Teamplay", "items": ["Scrim 5 set", "Post-match review", "Koordinasi strategi tim"]},{"dimension": "Kesehatan Fisik", "items": ["Stretching jari 15 menit", "Senam leher + bahu", "Istirahat mata 10 menit"]},{"dimension": "Streaming & Personal Branding", "items": ["Live streaming 2 jam", "Edit highlight reel", "Interaksi chat + komunitas"]},{"dimension": "Mental", "items": ["Meditasi 15 menit", "Review performa harian", "Diskusi taktik dengan coach"]}]'::jsonb,'[{"question": "Game kompetitif utama kamu?", "type": "single_select", "options": [{"label": "MOBA", "value": "moba"}, {"label": "FPS", "value": "fps"}, {"label": "Battle Royale", "value": "battle-royale"}, {"label": "Fighting", "value": "fighting"}]},{"question": "Level pengalaman e-sports?", "type": "single_select", "options": [{"label": "Pemula", "value": "pemula"}, {"label": "Rank tinggi", "value": "rank-tinggi"}, {"label": "Amateur", "value": "amateur"}, {"label": "Semi-pro", "value": "semi-pro"}]},{"question": "Target utama karir e-sports?", "type": "single_select", "options": [{"label": "Tim pro", "value": "tim-pro"}, 