options": [{"label": "Tim sekolah", "value": "tim-sekolah"}, {"label": "Liga kampus", "value": "liga-kampus"}, {"label": "Klub nasional", "value": "klub-nasional"}, {"label": "Timnas", "value": "timnas"}]},{"question": "Skill yang paling ingin kamu tingkatkan?", "type": "single_select", "options": [{"label": "Shooting", "value": "shooting"}, {"label": "Dribbling", "value": "dribbling"}, {"label": "Defense", "value": "defense"}, {"label": "Leadership", "value": "leadership"}]}]'::jsonb,'[{"title": "Pelatih Bola Basket", "description": "Melatih generasi muda pebasket dengan teknik dan strategi pro.", "slug": "alternative-basketball-coach"},{"title": "Komentator Olahraga", "description": "Membawakan analisis pertandingan basket yang seru dan mendalam.", "slug": "alternative-basketball-commentator"},{"title": "Management Sport Event", "description": "Mengorganisir turnamen dan event olahraga berskala nasional.", "slug": "alternative-sport-event-manager"}]'::jsonb);

